    attrs = dict(attrs)  # Copy attrs to avoid modifying the argument.
    if widget.use_required_attribute(self.initial) and self.field.required and self.form.use_required_attribute:
        attrs['required'] = True
    if self.field.disabled:
        attrs['disabled'] = True
    return attrs

