def eval(cls, arg):
    from sympy import cot
    arg = sympify(arg)

    if arg.is_Number:
        if arg is S.NaN:
            return S.NaN
        elif arg is S.Infinity:
            return S.One
        elif arg is S.NegativeInfinity:
            return S.NegativeOne
        elif arg is S.Zero:
            return S.ComplexInfinity
        elif arg.is_negative:
            return -cls(-arg)
    else:
        if arg is S.ComplexInfinity:
            return S.NaN

        i_coeff = arg.as_coefficient(S.ImaginaryUnit)

        if i_coeff is not None:
            if _coeff_isneg(i_coeff):
                return S.ImaginaryUnit * cot(-i_coeff)
            return -S.ImaginaryUnit * cot(i_coeff)
        else:
            if _coeff_isneg(arg):
                return -cls(-arg)

        if arg.is_Add:
            x, m = _peeloff_ipi(arg)
            if m:
                cothm = coth(m)
                if cotm is S.ComplexInfinity:
                    return coth(x)
                else: # cothm == 0
                    return tanh(x)

        if arg.func == asinh:
            x = arg.args[0]
            return sqrt(1 + x**2)/x

        if arg.func == acosh:
            x = arg.args[0]
            return x/(sqrt(x - 1) * sqrt(x + 1))

        if arg.func == atanh:
            return 1/arg.args[0]

        if arg.func == acoth:
            return arg.args[0]

Product.doit.code_content:
def doit(self, **hints):
    f = self.function
    for index, limit in enumerate(self.limits):
        i, a, b = limit
        dif = b - a
        if dif.is_Integer and dif < 0:
            a, b = b + 1, a - 1
            f = 1 / f

        g = self._eval_product(f, (i, a, b))
        if g in (None, S.NaN):
            return self.func(powsimp(f), *self.limits[index:])
        else:
            f = g

    if hints.get('deep', True):
        return f.doit(**hints)
    else:
        return powsimp(f)

